def vex_latency_guard(response, pipeline_latency):
    verdict = vex.verify({
        "type": "latency_check",
        "measured_latency": pipeline_latency,
        "budget": 500,  # ms
        "response": response
    })
    if not verdict["pass"]:
        return "[LATENCY_EXCEEDED] Processing..."
    return response

# Before TTS
